mapper.select:
/* SQL ID : LogSysJobSchExcDAO.list 설 명 : 업무일정 예외 로그 목록 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY Z.FRST_INQ_DTTM) AS LINE_NO , Z.* FROM ( SELECT (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE DEPT_CD = B.MNGT_DEPT_CD) AS DEPTNM , B.SBJCTNM , B.CRS_ID , B.DVCLAS_NO , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE RPRSYN = 'Y' AND PROF_TYCD = 'PROFESSOR' AND SBJCT_ID = B.SBJCT_ID)) AS TCH_NM , (SELECT USER_ID FROM SBJCT_PROF WHERE RPRSYN = 'Y' AND PROF_TYCD = 'PROFESSOR' AND SBJCT_ID = B.SBJCT_ID) AS TCH_NO , A.EXCP_LOG_CTS , A.RGTR_ID , A.FRST_INQ_DTTM FROM SYSJOB_SCHDL_EXCP_RCD A JOIN TB_LMS_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' WHERE 1 = 1
AND B.SBJCT_ID = #{creYear}
AND B.CRS_ID = #{creTerm}
AND B.UNIV_CD = #{uniCd}
AND B.UNIV_GBNCD = #{univGbn}
AND B.MNGT_DEPT_CD = #{mngtDeptCd}
ORDER BY A.FRST_INQ_DTTM DESC) Z WHERE 1 = 1
AND ( LOWER(Z.SBJCTNM) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(Z.CRS_ID) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(Z.TCH_NM) LIKE '%' || LOWER(#{searchValue}) || '%' )

